import React from "react";
import styleSign from "./SignOut.module.scss";
import { useHTTP } from "./../../.././hook/http";

const SignOut = () => {
  async function getListUsers() {
    const request = await fetch("http://localhost:5000/api/logoutUsers", {
      headers: {
        method: "GET",
        //@ts-ignore
        authorisation: JSON.parse(localStorage.getItem("user")).accessToken,
      },
    });
    return request;
  }
  const { request } = useHTTP();
  async function response(endPoint) {
    return await request(endPoint);
  }
  const toAuth = async (e) => {
    localStorage.removeItem("user");
    window.location.reload();
    try {
      await response("http://localhost:5000/api/logoutUsers");
    } catch (error) {
      console.log(error);
    }
  };
  return (
    <button onClick={toAuth} className={styleSign.container}>
      <p>Выйти</p>
      <svg width="25" height="25" fill="currentColor" viewBox="0 0 16 16">
        <path d="M6 12.5a.5.5 0 0 0 .5.5h8a.5.5 0 0 0 .5-.5v-9a.5.5 0 0 0-.5-.5h-8a.5.5 0 0 0-.5.5v2a.5.5 0 0 1-1 0v-2A1.5 1.5 0 0 1 6.5 2h8A1.5 1.5 0 0 1 16 3.5v9a1.5 1.5 0 0 1-1.5 1.5h-8A1.5 1.5 0 0 1 5 12.5v-2a.5.5 0 0 1 1 0v2z" />
        <path d="M.146 8.354a.5.5 0 0 1 0-.708l3-3a.5.5 0 1 1 .708.708L1.707 7.5H10.5a.5.5 0 0 1 0 1H1.707l2.147 2.146a.5.5 0 0 1-.708.708l-3-3z" />
      </svg>
    </button>
  );
};

export default SignOut;
